module packet_filtering (  
    input [4:0] disallowed_src,  
    input [4:0] dest_ip,  
    output reg allowed  
);  
    always @(*) begin  
        if ((disallowed_src >= 5 && disallowed_src <= 10) && (dest_ip == 15))  
            allowed = 1;  
        else  
            allowed = 0;  
    end  
endmodule
